import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { collection, onSnapshot } from 'firebase/firestore';
import { styles, tokens } from '../../styles';

const Dashboard = ({ setActiveTab, isAdmin, user }) => {
  const [employees, setEmployees] = useState([]);
  const [leaveRequests, setLeaveRequests] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [personalAttendance, setPersonalAttendance] = useState([]);
  const [holidays, setHolidays] = useState([]);

  useEffect(() => {
    const unsubEmp = onSnapshot(collection(db, 'employees'), s => setEmployees(s.docs.map(d => ({ id: d.id, ...d.data() }))));
    const unsubLeave = onSnapshot(collection(db, 'leaveRequests'), s => {
      const allLeaves = s.docs.map(d => d.data());
      if (isAdmin) {
        setLeaveRequests(allLeaves);
      } else {
        setLeaveRequests(allLeaves.filter(l => l.userEmail === user.email));
      }
    });
    const unsubAnnounce = onSnapshot(collection(db, 'announcements'), s => setAnnouncements(s.docs.map(d => ({ id: d.id, ...d.data() }))));
    const unsubHolidays = onSnapshot(collection(db, 'holidays'), s => setHolidays(s.docs.map(d => ({ id: d.id, ...d.data() }))));

    let unsubPersonalAtt;
    if (!isAdmin && user) {
      unsubPersonalAtt = onSnapshot(collection(db, 'attendance'), s => {
        setPersonalAttendance(s.docs.map(d => d.data()).filter(a => a.userEmail === user.email));
      });
    }

    return () => {
      unsubEmp(); unsubLeave(); unsubAnnounce(); unsubHolidays();
      if (unsubPersonalAtt) unsubPersonalAtt();
    };
  }, [isAdmin, user]);

  const currentUser = employees.find(e => e.email === user.email) || user;
  const deptColleagues = employees.filter(e => e.dept === currentUser.dept && e.email !== currentUser.email);

  const adminStats = [
    { label: 'Total Headcount', value: employees.length, icon: 'groups', color: tokens.colors.accent },
    { label: 'Pending Leaves', value: leaveRequests.filter(l => l.status === 'pending').length, icon: 'event_busy', color: tokens.colors.warning },
    { label: 'Monthly Payroll', value: `$${Math.round(employees.reduce((acc, curr) => acc + (Number(curr.salary) || 0), 0) / 12).toLocaleString()}`, icon: 'payments', color: tokens.colors.success },
  ];

  const today = new Date().toISOString().split('T')[0];
  const punchedInToday = personalAttendance.some(a => a.type === 'in' && a.timestamp?.toDate().toISOString().split('T')[0] === today);

  const upcomingHoliday = holidays
    .filter(h => new Date(h.date) >= new Date())
    .sort((a, b) => new Date(a.date) - new Date(b.date))[0];

  const employeeStats = [
    { label: 'Attendance Today', value: punchedInToday ? 'Clocked In' : 'Pending', icon: 'timer', color: punchedInToday ? tokens.colors.success : tokens.colors.warning },
    { label: 'Leave Balance', value: `${leaveRequests.filter(l => l.status === 'approved').length} / 12`, icon: 'beach_access', color: tokens.colors.accent },
    { label: 'Next Holiday', value: upcomingHoliday ? upcomingHoliday.name : 'None Scheduled', icon: 'celebration', color: tokens.colors.secondary },
  ];

  const stats = isAdmin ? adminStats : employeeStats;

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: '48px', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <h1 style={styles.greeting}>
            {isAdmin ? 'Executive Suite' : `Welcome back, ${currentUser.name?.split(' ')[0] || 'Staff'}`}
          </h1>
          <p style={{ color: tokens.colors.secondary, fontSize: '15px', marginTop: '4px' }}>
            {isAdmin ? 'Platform analytics and system health metrics at a glance.' : 'Have a productive day at HRMate.'}
          </p>
        </div>
        {!isAdmin && (
          <div style={{ ...styles.badge('primary'), padding: '10px 18px' }}>
            <span style={{ fontWeight: '700' }}>{currentUser.dept || 'Operations'}</span>
            <span style={{ margin: '0 8px', opacity: 0.3 }}>|</span>
            <span>{currentUser.role || 'Associate'}</span>
          </div>
        )}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '32px', marginBottom: '48px' }}>
        {stats.map(stat => (
          <div key={stat.label} style={{ ...styles.card, borderLeft: `4px solid ${stat.color || tokens.colors.accent}` }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontSize: '12px', fontWeight: '700', color: tokens.colors.secondary, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '12px' }}>{stat.label}</div>
                <div style={{ fontSize: '26px', fontWeight: '800', color: tokens.colors.primary }}>{stat.value}</div>
              </div>
              <div style={{
                width: '56px',
                height: '56px',
                background: `${stat.color}10`,
                borderRadius: tokens.radius.md,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '28px', color: stat.color }}>{stat.icon}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1.4fr 1fr', gap: '32px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '32px' }}>
          <div style={styles.card}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
              <div>
                <h3 style={{ fontSize: '18px', fontWeight: '800' }}>Organization Broadcasts</h3>
                <p style={{ fontSize: '13px', color: tokens.colors.secondary, marginTop: '2px' }}>Latest updates from HR and Management</p>
              </div>
              {isAdmin && (
                <button
                  onClick={() => setActiveTab('admin_broadcast')}
                  style={styles.button.ghost}
                >View Archives</button>
              )}
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
              {announcements.slice(0, 3).map(a => (
                <div key={a.id} style={{ padding: '20px', borderRadius: tokens.radius.md, backgroundColor: '#F8FAFC', border: `1px solid ${tokens.colors.border}`, transition: 'all 0.2s ease', cursor: 'default' }}>
                  <div style={{ fontWeight: '600', fontSize: '14px', marginBottom: '6px', color: tokens.colors.primary, lineHeight: '1.5' }}>{a.content}</div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '12px', color: tokens.colors.secondary }}>
                    <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>calendar_today</span>
                    {new Date(a.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                  </div>
                </div>
              ))}
              {announcements.length === 0 && (
                <div style={{ padding: '48px', textAlign: 'center' }}>
                  <div style={{ width: '64px', height: '64px', backgroundColor: '#F1F5F9', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}>
                    <span className="material-symbols-outlined" style={{ fontSize: '32px', color: '#CBD5E1' }}>notifications_off</span>
                  </div>
                  <div style={{ fontSize: '14px', fontWeight: '600', color: tokens.colors.secondary }}>Inbox Clear</div>
                  <div style={{ fontSize: '12px', color: tokens.colors.secondary }}>Check back later for system-wide updates.</div>
                </div>
              )}
            </div>
          </div>

          {!isAdmin && deptColleagues.length > 0 && (
            <div style={styles.card}>
              <h3 style={{ fontSize: '18px', fontWeight: '800', marginBottom: '24px' }}>Team Directory</h3>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '16px' }}>
                {deptColleagues.map(col => (
                  <div key={col.id} style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '12px', borderRadius: tokens.radius.md, border: `1px solid ${tokens.colors.border}`, backgroundColor: '#FFFFFF' }}>
                    <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: tokens.colors.accent + '15', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: '700', fontSize: '14px', color: tokens.colors.accent }}>
                      {col.name.charAt(0)}
                    </div>
                    <div style={{ overflow: 'hidden' }}>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: tokens.colors.primary, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{col.name}</div>
                      <div style={{ fontSize: '11px', color: tokens.colors.secondary, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{col.role}</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div style={{
          ...styles.card,
          backgroundColor: tokens.colors.primary,
          color: 'white',
          border: 'none',
          padding: '40px',
          backgroundImage: 'linear-gradient(135deg, #0F172A 0%, #1E293B 100%)',
          display: 'flex',
          flexDirection: 'column'
        }}>
          <h3 style={{ fontSize: '20px', fontWeight: '800', marginBottom: '8px' }}>
            {isAdmin ? 'System Terminal' : 'Quick Gateway'}
          </h3>
          <p style={{ color: '#94A3B8', marginBottom: '40px', fontSize: '14px', lineHeight: '1.5' }}>
            {isAdmin ? 'Access core management engine and organization oversight modules.' : 'Essential shortcuts for your daily workflow and personal requests.'}
          </p>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '12px' }}>
            {(isAdmin ? [
              { label: 'Policy Engine', icon: 'gavel', action: () => setActiveTab('admin_policies') },
              { label: 'Workforce Comms', icon: 'campaign', action: () => setActiveTab('admin_broadcast') },
              { label: 'Leave Requests', icon: 'event_available', action: () => setActiveTab('admin_leaves') },
              { label: 'Attendance Feed', icon: 'history', action: () => setActiveTab('admin_attendance') }
            ] : [
              { label: 'Access Punch Clock', icon: 'timer', action: () => setActiveTab('attendance') },
              { label: 'Request Time Off', icon: 'event_available', action: () => setActiveTab('leaves') },
              { label: 'Employee Profile', icon: 'person', action: () => setActiveTab('profile') },
              { label: 'Company Policies', icon: 'gavel', action: () => setActiveTab('admin_policies') }
            ]).map(tool => (
              <button
                key={tool.label}
                onClick={tool.action}
                style={{
                  padding: '16px 20px',
                  background: 'rgba(255, 255, 255, 0.05)',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                  color: 'white',
                  cursor: 'pointer',
                  borderRadius: tokens.radius.md,
                  display: 'flex',
                  alignItems: 'center',
                  gap: '16px',
                  transition: 'all 0.2s ease',
                  textAlign: 'left'
                }}
                onMouseOver={(e) => { e.currentTarget.style.background = 'rgba(255, 255, 255, 0.1)'; e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.2)'; }}
                onMouseOut={(e) => { e.currentTarget.style.background = 'rgba(255, 255, 255, 0.05)'; e.currentTarget.style.borderColor = 'rgba(255, 255, 255, 0.1)'; }}
              >
                <div style={{ width: '40px', height: '40px', background: 'rgba(255, 255, 255, 0.1)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>{tool.icon}</span>
                </div>
                <span style={{ fontWeight: '600', fontSize: '14px' }}>{tool.label}</span>
                <span className="material-symbols-outlined" style={{ marginLeft: 'auto', fontSize: '18px', opacity: 0.5 }}>chevron_right</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;